SELECT DISTINCT ?coach ?coachLabel
WHERE {
  wd:Q140148 wdt:P353 ?team .
  ?team p:P265 ?statement .
  ?statement ps:P265 ?coach .
  FILTER NOT EXISTS { ?statement pq:P585 ?end } .
  ?coach wdt:P912 ?team2 .
  ?team2 wdt:P353 wd:Q140148 .
  OPTIONAL { ?coach rdfs:label ?coachLabel . FILTER (lang(?coachLabel) = "en") }
}

